// Creating a Display List
DISPLAY_LIST squareList;
squareList = glGenLists(1);

// Begin defining the display list
glNewList(squareList, GL_COMPILE);
 glColor3f(1.0, 0.0, 0.0); // Red color
 glBegin(GL_POLYGON);
 glVertex2f(-1.0, -1.0);
 glVertex2f(1.0, -1.0);
 glVertex2f(1.0, 1.0);
 glVertex2f(-1.0, 1.0);
 glEnd();
glEndList();

// Executing the Display List
glCallList(squareList);

// Create hierarchical display lists for a robotic arm
DISPLAY_LIST base, arm1, arm2, gripper;

// Define base (stationary)
glNewList(base, GL_COMPILE);
 drawCylinder(0, 0, 0, 2.0, 1.0);
glEndList();

// Define arm1 (attached to base)
glNewList(arm1, GL_COMPILE);
 glTranslatef(0, 1.0, 0);
 drawRectangle(0.5, 2.0);
glEndList();

// Define arm2 (attached to arm1)
glNewList(arm2, GL_COMPILE);
 glTranslatef(0, 2.0, 0);
 drawRectangle(0.4, 1.5);
glEndList();

// Hierarchical rendering
glCallList(base); // Draw base
glPushMatrix();
 glRotatef(angle1, 0, 1, 0);
