// Create display list for complex object (e.g., a tree)
DISPLAY_LIST tree;
tree = glGenLists(1);

glNewList(tree, GL_COMPILE);
 // Draw tree trunk
 glColor3f(0.55, 0.27, 0.07);
 drawRectangle(0.3, 2.0);

