// Display list that includes state changes
DISPLAY_LIST coloredSquare;
coloredSquare = glGenLists(1);

glNewList(coloredSquare, GL_COMPILE);
 // State changes are also stored in the list
 glColor3f(1.0, 0.0, 0.0); // Red
 glBegin(GL_QUADS);
 glVertex2f(-0.5, -0.5);
 glVertex2f(0.5, -0.5);
 glVertex2f(0.5, 0.5);
 glVertex2f(-0.5, 0.5);
 glEnd();
glEndList();

// Executing with different preceding state
glColor3f(0.0, 0.0, 1.0); // Blue before call
glCallList(coloredSquare); // Draws red square (list overrides blue)

glColor3f(0.0, 1.0, 0.0); // Green before call
glCallList(coloredSquare); // Still draws red square (stored in list)
